from typing import List

class Solution:
    def bag(self, capacity: int, coins: List[int]) -> int:
        if capacity < 0 or not coins:
            return 0
        dp = [[0] * (capacity + 1) for _ in range(len(coins))]
        for i in range(len(coins)):
            for j in range(capacity + 1):
                if i == 0 or j < coins[i - 1]:
                    dp[i][j] = dp[i - 1][j]
                else:
                    dp[i][j] = max(dp[i - 1][j], dp[i - 1][j - coins[i - 1]] + 1)
        return dp[-1][-1]


if __name__ == '__main__':
    s = Solution()
    capacity = int(input())
    coins = list(map(int, input().split()))
    print(s.bag(capacity, coins))

