#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    int bag(int capacity, vector<int> coins) {
        if (capacity < 0 || coins.empty()) return 0;
        dp = Array(coins.size()).fill(0).map(() => Array(capacity + 1).fill(0));
        for (int i = 0; i < coins.size(); i++) {
            for (int j = 0; j <= capacity; j++) {
                if (i == 0 || j < coins[i]) {
                    dp[i][j] = dp[i - 1][j];
                } else {
                    dp[i][j] = max(dp[i - 1][j], dp[i - 1][j - coins[i]] + 1);
                }
            }
        }
        return dp.back().back();
    }
private:
    vector<vector<int>> dp;
};

int main() {
    Solution s;
    int capacity;
    cin >> capacity;
    int n;
    cin >> n;
    vector<int> coins(n);
    for (int i = 0; i < n; i++) {
        cin >> coins[i];
    }
    cout << s.bag(capacity, coins) << endl;
    return 0;
}
